## Code Example
```javascript
// Example WebSocket test skeleton using ws library
const WebSocket = require('ws');
const jwt = require('jsonwebtoken');

// Test client for WebSocket validation
const testWebSocketConnection = async (tenantId, token) => {
  const ws = new WebSocket(`ws://localhost/ws/updates?token=${token}`);

  ws.on('open', () => {
    console.log(`Connected for tenant: ${tenantId}`);
  });

  ws.on('message', (data) => {
    // Validate tenant isolation and message ordering
    const message = JSON.parse(data);
    console.log(`Received: ${message.sequenceId} for tenant: ${tenantId}`);
  });

  return ws;
};
```

